      if (lookahead == '\n') ADVANCE(97);
      if (lookahead == '[') ADVANCE(99);
      if (('\t' <= lookahead && lookahead <= '\r') ||
          lookahead == ' ') ADVANCE(96);
      if (lookahead != 0) ADVANCE(104);
      END_STATE();
    case 97:
      ACCEPT_TOKEN(sym_tagged_info);
      if (lookahead == '[') ADVANCE(34);
      if (('\t' <= lookahead && lookahead <= '\r') ||
          lookahead == ' ') ADVANCE(97);
