    case 99:
      ACCEPT_TOKEN(sym_message);
      if (lookahead == '\n') ADVANCE(34);
      if (lookahead == ']') ADVANCE(96);
      if (lookahead != 0) ADVANCE(99);
      END_STATE();
    case 100:
      ACCEPT_TOKEN(sym_message);
      if (lookahead == '\n') ADVANCE(75);
      if (lookahead == ':') ADVANCE(104);
      if (lookahead == '[') ADVANCE(89);
